.drop-zone {
    border: 2px dashed #6c757d;
    border-radius: 8px;
    padding: 2rem;
    text-align: center;
    color: #6c757d;
    transition: border-color 0.2s, background-color 0.2s;
    cursor: default;
}

.drop-zone:deep(.drag-over) {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.08);
    color: #0d6efd;
}

::deep .drag-over {
    border-color: #0d6efd;
    background-color: rgba(13, 110, 253, 0.08);
    color: #0d6efd;
}

.file-list {
    list-style: none;
    padding: 0;
    margin-top: 1rem;
}

.file-entry {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.5rem 0.75rem;
    border: 1px solid #dee2e6;
    border-radius: 4px;
    margin-bottom: 0.5rem;
}

.file-entry.file-error {
    border-color: #dc3545;
    background-color: #fff5f5;
}

.file-info {
    flex: 1;
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.error-message {
    color: #dc3545;
    font-weight: 500;
}

.btn-remove {
    margin-left: 1rem;
    padding: 0.25rem 0.75rem;
    border: 1px solid #dc3545;
    border-radius: 4px;
    background: transparent;
    color: #dc3545;
    cursor: pointer;
    flex-shrink: 0;
}

.btn-remove:hover {
    background-color: #dc3545;
    color: #fff;
}

